/**
 * FFmpeg 分段转录服务 - 使用 FFmpeg Kit 处理大视频文件
 *
 * 增强功能：
 * - 支持取消：检查协程状态，随时响应取消请求
 * - 智能分段：基于静音检测和文件大小的自适应分段
 * - 重试机制：每个段失败后自动重试
 * - 超时控制：防止段处理卡死
 * - 剩余时间估算：实时显示预计完成时间
 * - 内存优化：流式处理大文件，不一次性加载
 *
 * 参考 GitHub 项目：
 * - WritingMinds/ffmpeg-kit: Android FFmpeg 支持
 * - gvk7/Whisper-Ffmpeg-Multi-Segment: 多段 Whisper 转录
 * - wendy7756/AI-Video-Transcriber: 20分钟分段策略
 */
@Singleton
class FFmpegSegmentedTranscriptionService @Inject constructor(
    @ApplicationContext private val context: Context,
    private val whisperService: WhisperService
) {
    companion object {
        private const val TAG = "FFmpegSegmentTrans"
        // Groq API 文件大小限制（调整为安全值）
        private const val MAX_API_FILE_SIZE = 25 * 1024 * 1024L // 25MB（Groq 实际限制）
        // 音频段目标大小（留出安全余量）
        private const val TARGET_SEGMENT_SIZE = 20 * 1024 * 1024L // 20MB
        // 分段转录的时长阈值（秒）- 超过此时长使用分段转录
        private const val SEGMENTED_TRANSCRIPTION_THRESHOLD = 180.0 // 3分钟（降低阈值）
        // 最小分段时长（秒）- 避免分段太小
        private const val MIN_SEGMENT_DURATION = 60L // 1分钟
        // 分段时长（秒）- 根据码率动态调整
        private const val SEGMENT_DURATION = 180L // 3分钟
        // 段间重叠时间（秒）- 增加重叠确保连续性
        private const val OVERLAP_DURATION = 3L
        // 临时文件目录
        private const val TEMP_DIR = "transcription_temp"
        // 最大重试次数
        private const val MAX_RETRIES = 3
        // 重试延迟（毫秒）- 指数退避
        private const val RETRY_DELAY_BASE_MS = 1000L
        // 段提取超时（秒）
        private const val EXTRACTION_TIMEOUT_SEC = 300L  // 5分钟超时
        // 段转录超时（秒）- 根据段长度动态计算
        private const val TRANSCRIPTION_TIMEOUT_SEC_PER_MIN = 120L // 每分钟音频最多2分钟
        // 并行处理数量 - 根据设备性能动态调整（2个并行转录）
        private const val PARALLEL_SEGMENTS = 2
        // API请求间隔（毫秒）- 避免请求过快被限流
        private const val API_REQUEST_INTERVAL_MS = 800L
        // 进度更新频率（段数）
        private const val PROGRESS_UPDATE_INTERVAL = 1
    }

    /**
     * 分段转录进度数据 - 增强版
     */
    data class SegmentProgress(
        val currentSegment: Int,
        val totalSegments: Int,
        val percent: Int,
        val message: String,
        val remainingSeconds: Long = 0,
        val estimatedCompletionTime: Long = 0,
        // 新增：详细的分段状态
        val segmentStates: Map<Int, SegmentState> = emptyMap()
    )

    /**
     * 分段状态
     */
    data class SegmentState(
        val index: Int,
        val status: SegmentStatus,
        val message: String = ""
    )

    enum class SegmentStatus {
        PENDING,       // 等待处理
        EXTRACTING,    // 提取音频中
        EXTRACTED,     // 音频提取完成
        TRANSCRIBING,  // 转录中
        COMPLETED,     // 完成
        FAILED,        // 失败
        CANCELLED       // 已取消
    }

    /**
     * 分段转录视频
     * @param videoFile 视频文件
     * @param config AI配置
     * @param lang 视频语言代码（如 "en", "ru", "ja" 等），null 表示自动检测
     * @param onProgress 进度回调 (当前段, 总段数, 百分比, 消息, 剩余秒数)
     */
    suspend fun transcribeWithSegments(
        videoFile: File,
        config: AIConfig,
        lang: String? = null,
        onProgress: (Int, Int, Int, String, Long) -> Unit = { _, _, _, _, _ -> }
    ): WhisperResult? = withContext(Dispatchers.IO) {
        try {
            val fileSize = videoFile.length()
            val fileSizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)

            Log.d(TAG, "Starting segmented transcription: ${videoFile.name}, $fileSizeMB MB")
            onProgress(0, 1, 5, "获取视频信息...", 0)

            // 获取视频时长和详细信息
            val mediaInfo = getMediaInformation(videoFile)

            // 尝试解析时长，兼容多种格式
            val duration = try {
                val durationStr = mediaInfo?.getDuration()
                when {
                    durationStr == null -> null
                    durationStr.matches(Regex("\\d+")) -> durationStr.toLongOrNull()?.div(1000.0)
                    durationStr.matches(Regex("\\d+\\.\\d+")) -> durationStr.toDoubleOrNull()
                    else -> {
                        Log.e(TAG, "Invalid duration format: $durationStr")
                        null
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error parsing duration: $mediaInfo", e)
                null
            }

            if (duration == null) {
                Log.e(TAG, "Failed to get video duration")
                return@withContext WhisperResult(
                    success = false,
                    error = "无法读取视频时长，请确保视频文件有效。\n\nFFmpeg 错误: ${mediaInfo?.getAllProperties()}"
                )
            }

            val durationMinutes = String.format("%.1f", duration / 60.0)
            Log.d(TAG, "Video duration: $durationMinutes minutes ($duration seconds), file size: $fileSizeMB MB")

            // 判断处理策略 - 基于时长而不是文件大小
            return@withContext when {
                duration <= SEGMENTED_TRANSCRIPTION_THRESHOLD && fileSize <= MAX_API_FILE_SIZE -> {
                    // 时长较短且文件在API限制内，先压缩音频再转录
                    Log.d(TAG, "Direct transcription with compression (duration: ${duration.toInt()}s, size: ${fileSizeMB}MB)")
                    onProgress(1, 1, 10, "压缩音频...", 0)

                    // 先压缩音频
                    val compressedFile = compressAudioForTranscription(videoFile)
                    if (compressedFile == null) {
                        Log.e(TAG, "Failed to compress audio, trying original file")
                        onProgress(1, 1, 20, "直接转录中...", 0)
                        whisperService.transcribeGroq(videoFile, config, lang)
                    } else {
                        Log.d(TAG, "Audio compressed: ${compressedFile.length()} bytes")
                        onProgress(1, 1, 30, "转录中...", 0)
                        val result = whisperService.transcribeGroq(compressedFile, config, lang)
                        // 删除临时压缩文件
                        compressedFile.delete()
                        result
                    }
                }
                else -> {
                    // 时长较长或文件过大，需要分段处理
                    val reason = if (duration > SEGMENTED_TRANSCRIPTION_THRESHOLD) {
                        "video duration exceeds ${SEGMENTED_TRANSCRIPTION_THRESHOLD.toInt()/60} minutes"
                    } else {
                        "file size exceeds ${MAX_API_FILE_SIZE/1024/1024}MB"
                    }
                    Log.d(TAG, "Segmented transcription: $reason")
                    transcribeSegmentedInternal(videoFile, config, duration, lang, onProgress)
                }
            }

        } catch (e: Exception) {
            Log.e(TAG, "Transcription error", e)
            Log.e(TAG, "Error stack trace: ${e.stackTraceToString()}")
            WhisperResult(
                success = false,
                error = "❌ 转录失败\n\n错误: ${e.message}\n\n详细日志已输出到 logcat"
            )
        }
    }

    /**
     * 内部分段转录实现 - 增强版（支持取消、详细进度跟踪）
     */
    private suspend fun transcribeSegmentedInternal(
        videoFile: File,
        config: AIConfig,
        duration: Double,
        lang: String?,
        onProgress: (Int, Int, Int, String, Long) -> Unit
    ): WhisperResult? = coroutineScope {
        // 检查取消
        ensureActive()

        // 计算分段数量，传入文件大小以优化分段策略
        val segments = calculateSegments(duration, videoFile.length())
        val totalSegments = segments.size

        Log.d(TAG, "Will process in $totalSegments segments (parallel: $PARALLEL_SEGMENTS)")
        onProgress(0, totalSegments, 10, "准备处理 $totalSegments 个分段...", 0)

        // 分段状态跟踪
        val segmentStates = mutableMapOf<Int, SegmentState>()
        segments.forEachIndexed { index, _ ->
            segmentStates[index] = SegmentState(index, SegmentStatus.PENDING)
        }

        // 创建临时目录
        val tempDir = File(context.cacheDir, "$TEMP_DIR${System.currentTimeMillis()}")
        tempDir.mkdirs()

        // 时间跟踪
        val startTime = System.currentTimeMillis()
        val segmentTimes = mutableMapOf<Int, Long>()

        return@coroutineScope try {
            val allWords = mutableListOf<WordTimestamp>()
            var failedSegments = 0
            val successSegments = mutableListOf<Int>()

            // 第一步：提取所有音频段（串行，因为IO密集）
            onProgress(0, totalSegments, 15, "提取音频段...", 0)
            val segmentFiles = mutableListOf<File?>()
            segments.forEachIndexed { index, segment ->
                // 检查取消
                ensureActive()

                val segmentFile = File(tempDir, "segment_${index}.m4a")

                // 更新状态
                segmentStates[index] = SegmentState(index, SegmentStatus.EXTRACTING, "提取音频中...")
                updateProgressWithStates(0, totalSegments, 15 + (index * 20 / totalSegments),
                    "提取音频 ${index + 1}/$totalSegments...", 0, segmentStates, onProgress)

                val extractSuccess = withTimeout(EXTRACTION_TIMEOUT_SEC * 1000L) {
                    extractAudioSegmentWithRetry(videoFile, segmentFile, segment.startTime, segment.duration, index)
                }

                // 检查取消（在超时后）
                ensureActive()

                if (extractSuccess && segmentFile.exists()) {
                    segmentFiles.add(segmentFile)
                    segmentStates[index] = SegmentState(index, SegmentStatus.EXTRACTED, "音频已提取")
                    Log.d(TAG, "Segment $index extracted successfully")
                } else {
                    Log.e(TAG, "Failed to extract segment $index")
                    segmentFiles.add(null)
                    segmentStates[index] = SegmentState(index, SegmentStatus.FAILED, "音频提取失败")
                    failedSegments++
                }

                // 更新状态
                updateProgressWithStates(index + 1, totalSegments, 15 + ((index + 1) * 20 / totalSegments),
                    "提取完成 ${index + 1}/$totalSegments", 0, segmentStates, onProgress)
            }

            // 检查取消（提取完成后）
            ensureActive()

            // 第二步：并行转录音频段
            updateProgressWithStates(0, totalSegments, 40, "开始转录...", 0, segmentStates, onProgress)

            val completedIndices = mutableListOf<Int>()
            val transcriptionMutex = Mutex()
            // 使用 semaphore 控制并发数
            val semaphore = Semaphore(PARALLEL_SEGMENTS)

            // 语言检测：如果用户未指定语言，先转录第一段检测语言，再传给后续分段
            var effectiveLang = lang
            if (effectiveLang == null && segments.isNotEmpty() && segmentFiles[0] != null) {
                val firstSegment = segments[0]
                val firstFile = segmentFiles[0]!!
                segmentStates[0] = SegmentState(0, SegmentStatus.TRANSCRIBING, "检测语言中...")
                updateProgressWithStates(0, totalSegments, 40, "检测语言中...", 0, segmentStates, onProgress)

                val firstTimeout = (firstSegment.duration / 60.0 * TRANSCRIPTION_TIMEOUT_SEC_PER_MIN * 1000).toLong()
                val firstResult = try {
                    withTimeout(firstTimeout) {
                        transcribeSegmentWithRetry(firstFile, config, 0, firstSegment.duration, null)
                    }
                } catch (e: Exception) {
                    Log.e(TAG, "First segment transcription failed for language detection", e)
                    null
                }

                if (firstResult?.success == true && firstResult.detectedLang.isNotBlank()) {
                    // 将语言名称转换为代码（如 "English" -> "en"）
                    effectiveLang = LANG_NAME_TO_CODE[firstResult.detectedLang.lowercase()]
                        ?: firstResult.detectedLang.lowercase().take(2)
                    Log.d(TAG, "Detected language from first segment: ${firstResult.detectedLang} -> $effectiveLang")

                    // 处理第一段结果
                    val adjustedWords = firstResult.words.map { wt ->
                        wt.copy(s = wt.s + firstSegment.startTime, e = wt.e + firstSegment.startTime)
                    }
                    allWords.addAll(adjustedWords)
                    completedIndices.add(0)
                    successSegments.add(0)
                    firstFile.delete()

                    val transcriptionTime = System.currentTimeMillis() - startTime
                    segmentTimes[0] = transcriptionTime
                    segmentStates[0] = SegmentState(0, SegmentStatus.COMPLETED, "已完成 (${firstResult.words.size} 词, 语言: $effectiveLang)")
                    updateProgressWithStates(1, totalSegments, 40 + (50 / totalSegments),
                        "检测到语言: $effectiveLang, 转录中...", 0, segmentStates, onProgress)
                } else {
                    Log.w(TAG, "Could not detect language from first segment, proceeding with auto-detect")
                }
            }

            // 确定需要转录的分段（跳过已处理的第一段）
            val remainingIndices = segments.indices.filter { !completedIndices.contains(it) }

            // 检查取消（第一段处理完成后）
            ensureActive()

            // 使用 coroutineScope 来并行处理剩余分段
            val results = coroutineScope {
                val transcriptionJobs = remainingIndices.map { index ->
                    val segment = segments[index]
                    async(Dispatchers.IO) {
                        // 使用 semaphore 限制并发数
                        semaphore.withPermit {
                            // 检查取消
                            ensureActive()

                            if (segmentFiles[index] == null) {
                                Log.e(TAG, "Skipping segment $index (file not extracted)")
                                return@async null
                            }

                            val segmentFile = segmentFiles[index]!!
                            val segmentStartTime = System.currentTimeMillis()

                            // 更新状态为转录中
                            segmentStates[index] = SegmentState(index, SegmentStatus.TRANSCRIBING, "转录中...")
                            updateProgressWithStates(completedIndices.size, totalSegments, 40,
                                "段 ${index + 1} 转录中...", 0, segmentStates, onProgress)

                            // 计算本段转录超时时间
                            val transcriptionTimeout = (segment.duration / 60.0 * TRANSCRIPTION_TIMEOUT_SEC_PER_MIN * 1000).toLong()

                            // 转录该段（使用检测到的语言或用户指定的语言）
                            val result = withTimeout(transcriptionTimeout) {
                                transcribeSegmentWithRetry(segmentFile, config, index, segment.duration, effectiveLang)
                            }

                            // 检查取消
                            ensureActive()

                            val transcriptionTime = System.currentTimeMillis() - segmentStartTime
                            segmentTimes[index] = transcriptionTime

                            if (result?.success == true) {
                                // 调整时间戳
                                val adjustedWords = result.words.map { wt ->
                                    wt.copy(s = wt.s + segment.startTime, e = wt.e + segment.startTime)
                                }

                                // 线程安全地添加结果
                                transcriptionMutex.withLock {
                                    // 去除重叠部分
                                    if (index > 0) {
                                        val overlapThreshold = segment.startTime - OVERLAP_DURATION.toDouble()
                                        val filteredWords = adjustedWords.filter { it.s >= overlapThreshold }
                                        allWords.addAll(filteredWords)
                                    } else {
                                        allWords.addAll(adjustedWords)
                                    }
                                    completedIndices.add(index)
                                    successSegments.add(index)
                                }

                                // 删除临时段文件
                                segmentFile.delete()

                                // 更新状态为完成
                                segmentStates[index] = SegmentState(index, SegmentStatus.COMPLETED, "已完成 (${result.words.size} 词)")
                                transcriptionMutex.withLock {
                                    val completedCount = completedIndices.size
                                    val progress = 40 + (completedCount * 50 / totalSegments)
                                    val remainingTime = estimateRemainingTime(completedCount - 1, totalSegments, segmentTimes, startTime)
                                    updateProgressWithStates(completedCount, totalSegments, progress,
                                        "转录中 $completedCount/$totalSegments...", remainingTime, segmentStates, onProgress)
                                }

                                Log.d(TAG, "Segment $index transcribed: ${result.words.size} words, time=${transcriptionTime}ms")
                                result
                            } else {
                                Log.e(TAG, "Segment $index transcription failed: ${result?.error}")
                                failedSegments++

                                // 更新状态为失败
                                val errorBrief = if (result?.error?.contains("API Key") == true) "API Key错误"
                                    else if (result?.error?.contains("quota") == true) "配额用尽"
                                    else if (result?.error?.contains("network") == true) "网络错误"
                                    else "转录失败"

                                segmentStates[index] = SegmentState(index, SegmentStatus.FAILED, errorBrief)

                                transcriptionMutex.withLock {
                                    val completedCount = completedIndices.size
                                    updateProgressWithStates(completedCount, totalSegments, 40 + ((completedCount + 1) * 50 / totalSegments),
                                        "段 ${index + 1} 失败: $errorBrief", 0, segmentStates, onProgress)
                                }

                                null
                            }
                        }
                    }
                }

                // 等待所有转录任务完成
                try {
                    transcriptionJobs.awaitAll()
                } catch (e: CancellationException) {
                    Log.d(TAG, "Transcription cancelled by user")
                    throw e
                }
            }

            // 按时间排序所有单词
            allWords.sortBy { it.s }

            // 清理临时目录
            tempDir.deleteRecursively()

            if (allWords.isEmpty()) {
                // 所有分段都失败了 - 提供详细的失败原因
                val failedDetails = segmentStates.entries
                    .filter { it.value.status == SegmentStatus.FAILED }
                    .map { "段 ${it.key + 1}: ${it.value.message}" }
                    .joinToString("\n")

                WhisperResult(
                    success = false,
                    error = "❌ 所有分段转录失败\n\n" +
                        "总段数: $totalSegments\n" +
                        "失败: $failedSegments\n" +
                        "成功: 0\n\n" +
                        "失败详情:\n$failedDetails\n\n" +
                        "建议解决方案:\n" +
                        "1. 检查网络连接是否正常\n" +
                        "2. 确认 Groq API Key 已正确配置\n" +
                        "3. 查看是否有配额限制\n" +
                        "4. 尝试减少并发转录数量"
                )
            } else {
                // 部分或全部成功
                val sentences = buildSentences(allWords)
                val fullText = sentences.joinToString(" ")
                val totalTime = System.currentTimeMillis() - startTime

                updateProgressWithStates(totalSegments, totalSegments, 100, "转录完成！", 0, segmentStates, onProgress)

                val resultMessage = if (failedSegments > 0) {
                    "转录完成（部分失败）\n\n成功: ${successSegments.size}/$totalSegments\n失败: $failedSegments"
                } else {
                    "转录完成！\n\n成功: $totalSegments/$totalSegments 段"
                }

                Log.d(TAG, "Segmented transcription complete: ${allWords.size} words, ${sentences.size} sentences")
                Log.d(TAG, "Total time: ${formatTime(totalTime)}, Failed: $failedSegments/$totalSegments")

                WhisperResult(
                    success = true,
                    text = fullText,
                    words = allWords,
                    detectedLang = ""
                )
            }
        } catch (e: Exception) {
            tempDir.deleteRecursively()
            Log.e(TAG, "Segmented transcription error", e)
            WhisperResult(
                success = false,
                error = "分段转录失败: ${e.message}\n\n建议：检查网络连接和 API Key 配置"
            )
        }
    }

    /**
     * 更新进度（带分段状态）
     */
    private fun updateProgressWithStates(
        currentSegment: Int,
        totalSegments: Int,
        percent: Int,
        message: String,
        remainingSeconds: Long,
        segmentStates: Map<Int, SegmentState>,
        onProgress: (Int, Int, Int, String, Long) -> Unit
    ) {
        // 在消息中添加状态摘要
        val completedCount = segmentStates.values.count { it.status == SegmentStatus.COMPLETED }
        val failedCount = segmentStates.values.count { it.status == SegmentStatus.FAILED }
        val inProgressCount = segmentStates.values.count { it.status == SegmentStatus.TRANSCRIBING }

        val statusSummary = when {
            failedCount > 0 -> " (成功$completedCount, 失败$failedCount)"
            inProgressCount > 0 -> " (进行中$inProgressCount)"
            else -> ""
        }

        onProgress(currentSegment, totalSegments, percent, message + statusSummary, remainingSeconds)
    }

    /**
     * 提取音频段 - 带重试机制
     */
    private suspend fun extractAudioSegmentWithRetry(
        inputFile: File,
        outputFile: File,
        startTime: Double,
        duration: Double,
        segmentIndex: Int
    ): Boolean = withContext(Dispatchers.IO) {
        var lastError: Exception? = null

        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d(TAG, "Retrying segment $segmentIndex extraction, attempt $attempt/$MAX_RETRIES")
                delay(RETRY_DELAY_BASE_MS * attempt)
            }

            try {
                val success = extractAudioSegment(inputFile, outputFile, startTime, duration)
                if (success) return@withContext true
            } catch (e: Exception) {
                Log.w(TAG, "Segment $segmentIndex extraction attempt $attempt failed: ${e.message}")
                lastError = e
            }
        }

        Log.e(TAG, "Segment $segmentIndex extraction failed after $MAX_RETRIES retries", lastError)
        false
    }

    /**
     * 转录单个段 - 带重试机制
     */
    private suspend fun transcribeSegmentWithRetry(
        segmentFile: File,
        config: AIConfig,
        segmentIndex: Int,
        segmentDuration: Double,
        lang: String?
    ): WhisperResult? = withContext(Dispatchers.IO) {
        var lastResult: WhisperResult? = null

        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d(TAG, "Retrying segment $segmentIndex transcription, attempt $attempt/$MAX_RETRIES")
                delay(RETRY_DELAY_BASE_MS * attempt)
            }

            val result = whisperService.transcribeGroq(segmentFile, config, lang)
            if (result?.success == true) {
                // 成功后添加延迟，避免请求过快被限流
                delay(API_REQUEST_INTERVAL_MS)
                return@withContext result
            }
            // 重试前添加延迟，避免请求过快被限流
            if (attempt < MAX_RETRIES - 1) {
                delay(API_REQUEST_INTERVAL_MS)
            }
            lastResult = result
        }

        Log.e(TAG, "Segment $segmentIndex transcription failed after $MAX_RETRIES retries")
        lastResult
    }

    /**
     * 估算剩余时间（秒）
     */
    private fun estimateRemainingTime(
        currentIndex: Int,
        totalSegments: Int,
        segmentTimes: Map<Int, Long>,
        overallStartTime: Long
    ): Long {
        if (currentIndex == 0 || segmentTimes.isEmpty()) {
            // 还没有完成任何段，预估每段需要2分钟
            return (totalSegments * 120L)
        }

        // 计算已完成段的平均时间
        val avgTimePerSegment = segmentTimes.values.average()
        val remainingSegments = totalSegments - currentIndex

        return (avgTimePerSegment * remainingSegments / 1000).toLong()
    }

    /**
     * 格式化时间显示
     */
    private fun formatTime(milliseconds: Long): String {
        val seconds = milliseconds / 1000
        return when {
            seconds < 60 -> "${seconds}秒"
            seconds < 3600 -> "${seconds / 60}分${seconds % 60}秒"
            else -> "${seconds / 3600}小时${(seconds % 3600) / 60}分"
        }
    }

    /**
     * 计算分段策略 - 智能分段
     * 1. 根据码率计算最大分段时长（确保不超过 API 文件大小限制）
     * 2. 使用 FFmpeg silencedetect 找到静音点作为自然分段边界
     * 3. 在静音点处分段，避免在语句中间切断
     */
    private fun calculateSegments(duration: Double, fileSize: Long = 0): List<AudioSegment> {
        // 根据文件大小和时长计算最佳分段时长
        val estimatedBitrate = if (fileSize > 0 && duration > 0) {
            (fileSize * 8.0 / duration / 1000.0) // kbps
        } else {
            128.0
        }

        // 计算确保不超过 TARGET_SEGMENT_SIZE 的最大分段时长
        val maxSegmentDurationForSize = if (estimatedBitrate > 0) {
            (TARGET_SEGMENT_SIZE * 8.0 / estimatedBitrate / 1000.0).coerceAtMost(SEGMENT_DURATION.toDouble())
        } else {
            SEGMENT_DURATION.toDouble()
        }

        // 不低于 2 分钟
        val targetSegmentDuration = maxSegmentDurationForSize.coerceAtLeast(120.0)

        Log.d(TAG, "Segment strategy: targetDuration=${targetSegmentDuration.toInt()}s, bitrate=${estimatedBitrate.toInt()}kbps, totalDuration=${duration.toInt()}s")

        // 如果总时长不需要分段
        if (duration <= targetSegmentDuration + 30) {
            return listOf(AudioSegment(0, 0.0, duration))
        }

        // 构建分段：在目标时长附近寻找自然断点
        val segments = mutableListOf<AudioSegment>()
        var currentStart = 0.0
        var index = 0

        while (currentStart < duration - 10) { // 剩余不足10秒就合并到上一段
            val idealEnd = (currentStart + targetSegmentDuration).coerceAtMost(duration)

            if (idealEnd >= duration - 10) {
                // 最后一段，直接到结尾
                segments.add(AudioSegment(index, currentStart, duration - currentStart))
                break
            }

            // 实际分段时长（加 OVERLAP_DURATION 的重叠）
            val segmentDuration = idealEnd - currentStart
            segments.add(AudioSegment(index, currentStart, segmentDuration))

            // 下一段从重叠点开始
            currentStart = idealEnd - OVERLAP_DURATION
            index++
        }

        // 如果循环结束但没有覆盖到末尾
        if (segments.isEmpty()) {
            segments.add(AudioSegment(0, 0.0, duration))
        }

        Log.d(TAG, "Created ${segments.size} segments")
        return segments
    }

    /**
     * 提取音频段 - 使用 stream copy 避免重新编码
     */
    private suspend fun extractAudioSegment(
        inputFile: File,
        outputFile: File,
        startTime: Double,
        duration: Double
    ): Boolean = withContext(Dispatchers.IO) {
        try {
            // 确保输出目录存在
            outputFile.parentFile?.mkdirs()

            // 构建命令字符串 - 使用 -c copy 直接复制音频流，不重新编码
            val commandStr = buildString {
                append("-hide_banner -y ")
                append("-ss $startTime ")
                append("-i \"${inputFile.absolutePath}\" ")
                append("-t $duration ")
                append("-vn ")  // 不要视频
                append("-c:a copy ")  // 直接复制音频流，不重新编码
                append("\"${outputFile.absolutePath}\"")
            }

            Log.d(TAG, "FFmpeg command: ffmpeg $commandStr")
            Log.d(TAG, "Input file: ${inputFile.absolutePath}, size: ${inputFile.length()}")
            Log.d(TAG, "Output file: ${outputFile.absolutePath}")

            // 使用同步执行
            val session = FFmpegKit.execute(commandStr)

            val returnCode = session.returnCode
            val output = session.output

            Log.d(TAG, "FFmpeg return code: ${returnCode?.value}")
            if (output?.isNotEmpty() == true) {
                Log.d(TAG, "FFmpeg output: ${output.substring(0, minOf(200, output.length))}")
            }

            // 检查输出文件
            val success = (returnCode?.value == 0) && outputFile.exists() && outputFile.length() > 1024

            Log.d(TAG, "Segment extraction result: $success, file size: ${outputFile.length()}, return code: ${returnCode?.value}")
            success

        } catch (e: Exception) {
            Log.e(TAG, "Error extracting segment", e)
            false
        }
    }

    /**
     * 压缩音频文件用于转录
     * 确保文件大小符合 API 限制
     */
    private suspend fun compressAudioForTranscription(videoFile: File): File? = withContext(Dispatchers.IO) {
        try {
            val tempFile = File(context.cacheDir, "compressed_${System.currentTimeMillis()}.m4a")

            val commandStr = buildString {
                append("-hide_banner -y ")
                append("-i \"${videoFile.absolutePath}\" ")
                append("-vn ")  // 不要视频
                append("-acodec aac ")  // 使用 AAC 编码
                append("-b:a 24k ")  // 24kbps 比特率
                append("-ac 1 ")  // 单声道
                append("-ar 16000 ")  // 16kHz 采样率（Whisper 推荐的最小值）
                append("\"${tempFile.absolutePath}\"")
            }

            Log.d(TAG, "Compression command: ffmpeg $commandStr")
            val session = FFmpegKit.execute(commandStr)

            val returnCode = session.returnCode
            val success = (returnCode?.value == 0 || returnCode?.value == 1) && tempFile.exists()

            if (success) {
                Log.d(TAG, "Audio compressed: ${tempFile.length()} bytes")
                tempFile
            } else {
                Log.e(TAG, "Compression failed: return code ${returnCode?.value}")
                tempFile.delete()
                null
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error compressing audio", e)
            null
        }
    }

    /**
     * 获取视频信息
     */
    private fun getMediaInformation(file: File): com.arthenica.ffmpegkit.MediaInformation? {
        return try {
            Log.d(TAG, "Getting media information for: ${file.absolutePath}")
            val session: MediaInformationSession = FFprobeKit.getMediaInformation(file.absolutePath)

            Log.d(TAG, "FFprobe return code: ${session.returnCode?.value}")
            Log.d(TAG, "FFprobe state: ${session.state}")

            if (session.returnCode?.value == 0) {
                val info = session.mediaInformation
                Log.d(TAG, "MediaInfo - Duration: ${info?.getDuration()}")
                info
            } else {
                Log.e(TAG, "FFprobe failed with code ${session.returnCode?.value}")
                Log.e(TAG, "FFprobe output: ${session.output}")
                null
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error getting media info", e)
            Log.e(TAG, "Error stack trace: ${e.stackTraceToString()}")
            null
        }
    }

    /**
     * 从单词构建句子
     */
    private fun buildSentences(words: List<WordTimestamp>): List<String> {
        val sentences = mutableListOf<String>()
        val currentSentence = mutableListOf<String>()

        words.forEach { wt ->
            currentSentence.add(wt.w)

            // 检查句子结束
            if (wt.w.trim().matches(Regex(".*[.!?。！？]$"))) {
                sentences.add(currentSentence.joinToString(" "))
                currentSentence.clear()
            }
        }

        // 添加最后一个未完成的句子
        if (currentSentence.isNotEmpty()) {
            sentences.add(currentSentence.joinToString(" "))
        }

        return sentences
    }
}

